-- Certificates
CREATE TABLE IF NOT EXISTS certifications (
  id INT PRIMARY KEY,
  code VARCHAR(100),
  customer_id INT,
  status INT,
  issue_date DATE,
  service_date DATE,
  document_type INT,
  user_id INT,
  pdf_document_path TEXT,
  request_number VARCHAR(100)
